var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"어떻게 된 거야, 이 늙은이? 끌고 오는 내내 반항 한 번 안 하네.","JPN":"どうしたんだ、この老いぼれ。ここまで来る途中、一度も抵抗しなかったぞ。","ENG":"What's with this old hag? She hasn't resisted once the whole time we dragged her here.","TWN":"那個老太婆怎麼回事？這一路上竟然沒有一絲反抗。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"사람 죽는 꼴을 보고 정신이 나간 거겠지.","JPN":"人が死ぬ様を見て気が抜けたんだろ？","ENG":"She's just out of it after seeing people die in front of her.","TWN":"可能是看到那麼多人慘死被嚇到吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"아니면 살기를 포기했거나.","JPN":"生きることを諦めたとか。","ENG":"That, or she's given up on life.","TWN":"或是已經失去求生意志。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"내버려 둬. 그 나이에 살겠다고 발버둥치는 것도 꼴사나워.","JPN":"放っておけ。その年で生きようと足掻く程醜いこともない。","ENG":"Leave her be. It's unsightly for someone that old to keep struggling to stay alive, anyway.","TWN":"別管她，都活到這把年紀還在乎活命豈不是很難看。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"교전에 투입한 융합체들의 신호는 잡히고 있어?","JPN":"交戦に投入した融合体たちの信号は？","ENG":"Are you getting a signal for the hybriders we deployed to battle?","TWN":"有掌握到投入戰場的融合體訊號嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그게……. 저희가 기지에 도착했을 때는 전부 두절된 이후였습니다.","JPN":"それが……我々が基地に着いた時には、すでにすべて途絶えていました。","ENG":"Well... by the time we arrived, their signals had already been disconnected.","TWN":"這個……在我們抵達基地後就完全失去訊號。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그래?","JPN":"ほう？","ENG":"Really?","TWN":"是嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"의외의 결과네. 이번에 투입한 융합체들은 하이드리히 경의 개량형이었잖아?","JPN":"意外な結果だな。今回投入した融合体はすべて、ハイドリヒ卿の改良型だっただろう？","ENG":"That's unexpected. But wasn't this group of hybriders modified by Sir Heydrich?","TWN":"出乎我意料，這次投入的融合體可是海德里希的改良型呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"걱정 마십시오. 지금 교전 데이터를 수집 중입니다.","JPN":"ご心配には及びません。今、交戦データを収集中です。","ENG":"Don't worry, sir. Their battle data is being collected now.","TWN":"不要擔心，目前正在收集交戰資料。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"하이드리히 경 덕분에 융합체 개량은 새로운 국면을 맞이했습니다.","JPN":"ハイドリヒ卿のおかげで、融合体の改良は新局面を迎えました。","ENG":"Thanks to Sir Heydrich, we entered a new era of hybrider modification.","TWN":"拜海德里希所賜，融合體的改良才能有新的突破。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"시간과 예산만 더 주어진다면…. 어쩌면 카운터를 능가할 수 있을지도…….","JPN":"時間と予算の余裕さえあれば……もしかすると、カウンターを越えることができるかも……","ENG":"With more budget and time... they might even surpass Counters...","TWN":"如果有充分的時間和預算，甚至有可能超越制裁者……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"시간과 예산은 항상 부족했어. 앞으로도 그럴 테고.","JPN":"時間と予算はいつもギリギリだった。この先もそれは変わらないだろう。","ENG":"We were always short on both funds and time. And that will not change anytime soon.","TWN":"時間和預算不可能充分，以後也一樣。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그래서 저 늙은이가 필요한 거야. 활용하기에 따라선 그로니아와 북방합의체 양측의 지원을 요구할 수 있을 테니까.","JPN":"だからあの老いぼれが必要なんだ。使い方によっては、グロニアと北方合意体、両方からの援助を要求できるはずだからな。","ENG":"That's why we need that old woman. If we use our cards right, we'll be able to ask for resources from both Gronia and the Northern Union.","TWN":"所以我們才需要那老太婆。我們可以利用她來向格羅尼亞和北方和議會要求支援。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그건…. 다른 간부 분들과 논의하지 않으셔도 되겠습니까?","JPN":"それは……他の幹部の方々と議論しなくてもいいのですか？","ENG":"Do you... not need to discuss that with the other officials first?","TWN":"這……真的不用和其他幹部討論嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"말씀을 들을수록 저희 선에서 단독으로 추진하기엔 위험이 커 보입니다.","JPN":"話を聞けば聞くほど、我々の線で単独的に仕事を進めるにはあまりにも危険かと思われますが。","ENG":"The more I hear about it, the more I think that it will be risky for us to carry this out on our own.","TWN":"越聽你的話就越覺得，我們如果獨斷實行這個方案，會有很大的風險。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하, 겁먹지 마.","JPN":"はは、怖がるなよ。","ENG":"Haha, don't be so worried.","TWN":"哈哈，不用怕。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"장부는 과단성을 발휘해야 할 때가 있어. 관리국이 자멸할 때까지 소인배처럼 웅크리고 있자는 건가?","JPN":"漢は果敢に行動しなければならない時があるんだ。管理局が自滅するまで、臆病者みたいに縮こまっていろとでも言うのか？","ENG":"There are times when a man must be decisive. Or do you want to crawl and hide like a worm until the Administration implodes?","TWN":"大丈夫有時候必須當機立斷。難道要像一個膽小鬼一樣等待管理局自取滅亡嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};